// 🤖 AI增强的指令解析和验证
const input = $json;

// 支持的控制类型
const controlTypes = {
  voice: '语音控制',
  text: '文本控制',
  automation: '自动化触发',
  schedule: '定时任务',
  sensor: '传感器触发'
};

// 支持的设备类别
const deviceCategories = {
  light: { type: 'light', domain: 'light', actions: ['turn_on', 'turn_off', 'toggle', 'brightness', 'color'] },
  climate: { type: 'climate', domain: 'climate', actions: ['turn_on', 'turn_off', 'set_temperature', 'set_mode'] },
  switch: { type: 'switch', domain: 'switch', actions: ['turn_on', 'turn_off', 'toggle'] },
  fan: { type: 'fan', domain: 'fan', actions: ['turn_on', 'turn_off', 'set_speed'] },
  cover: { type: 'cover', domain: 'cover', actions: ['open_cover', 'close_cover', 'stop_cover'] },
  media_player: { type: 'media_player', domain: 'media_player', actions: ['play', 'pause', 'stop', 'volume_up', 'volume_down'] }
};

// AI自然语言处理（简化版，可集成真正的NLP）
function parseNaturalLanguage(text) {
  const lower = text.toLowerCase();
  let intent = {};

  // 识别动作
  if (lower.includes('打开') || lower.includes('开启') || lower.includes('turn on')) {
    intent.action = 'turn_on';
  } else if (lower.includes('关闭') || lower.includes('关掉') || lower.includes('turn off')) {
    intent.action = 'turn_off';
  } else if (lower.includes('切换') || lower.includes('toggle')) {
    intent.action = 'toggle';
  }

  // 识别设备类型
  if (lower.includes('灯') || lower.includes('light')) {
    intent.device_type = 'light';
  } else if (lower.includes('空调') || lower.includes('climate') || lower.includes('ac')) {
    intent.device_type = 'climate';
  } else if (lower.includes('开关') || lower.includes('switch')) {
    intent.device_type = 'switch';
  } else if (lower.includes('窗帘') || lower.includes('curtain') || lower.includes('cover')) {
    intent.device_type = 'cover';
  }

  // 识别位置
  const rooms = ['客厅', '卧室', '厨房', '卫生间', '书房', 'living room', 'bedroom', 'kitchen'];
  for (const room of rooms) {
    if (lower.includes(room)) {
      intent.room = room;
      break;
    }
  }

  return intent;
}

// 验证和处理输入
let command = {
  timestamp: new Date().toISOString(),
  request_id: `REQ-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
  source: input.source || 'manual',
  ha_url: input.ha_url || process.env.HA_URL || 'http://localhost:8123',
  ha_token: input.ha_token || process.env.HA_TOKEN,
  user: input.user || 'system'
};

// 智能解析
if (input.natural_language || input.voice_text) {
  // AI自然语言处理
  const nlpResult = parseNaturalLanguage(input.natural_language || input.voice_text);
  command = { ...command, ...nlpResult, nl_input: input.natural_language || input.voice_text };
} else {
  // 结构化命令
  command.device_type = input.device_type;
  command.action = input.action;
  command.entity_id = input.entity_id;
  command.room = input.room;
}

// 参数处理
if (input.parameters) {
  command.parameters = input.parameters;
}

// 验证必填字段
if (!command.action && !command.nl_input) {
  throw new Error('必须提供 action 或 natural_language 指令');
}

// 获取设备信息
if (command.device_type && deviceCategories[command.device_type]) {
  command.device_info = deviceCategories[command.device_type];
}

// AI优先级评估
command.priority = input.priority || (command.source === 'automation' ? 'high' : 'normal');

// 场景识别
if (input.scene) {
  command.scene = input.scene;
  command.is_scene = true;
}

return { json: command };

// 📊 智能日志和分析
const command = $('🤖 AI指令解析器').item.json;
const response = $json;

const log = {
  request_id: command.request_id,
  timestamp: command.timestamp,
  completed_at: new Date().toISOString(),
  execution_time: Date.now() - new Date(command.timestamp).getTime(),
  user: command.user,
  source: command.source,
  command_type: command.is_scene ? 'scene' : 'device_control',
  device_type: command.device_type,
  action: command.action,
  scene: command.scene,
  nl_input: command.nl_input,
  entity_id: command.entity_id,
  room: command.room,
  priority: command.priority,
  success: response.statusCode >= 200 && response.statusCode < 300,
  status_code: response.statusCode,
  response_body: response.body
};

// AI学习数据（可存储用于改进）
log.learning_data = {
  user_pattern: `${command.user}_${command.device_type}_${command.action}`,
  time_of_day: new Date().getHours(),
  day_of_week: new Date().getDay(),
  frequency: 1  // 可累加
};

return { json: log };

// 🚨 错误处理和通知
const error = $json.error || $json;
const command = $('🤖 AI指令解析器').item.json;

const errorLog = {
  request_id: command.request_id,
  timestamp: new Date().toISOString(),
  user: command.user,
  command: JSON.stringify(command),
  error_message: error.message || String(error),
  error_stack: error.stack || '',
  retry_count: 0
};

return { json: errorLog };
